export type Snippet = {
  id: string
  title: string
  language: string
  tags: string[]
  code: string
  createdAt: string
}

export type SnippetInput = {
  title: string
  language: string
  tags: string
  code: string
}

export type FilterState = {
  language: string
  tag: string
}

import type { Snippet, SnippetInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/snippets.jsonl`

export const generateId = (): string =>
  crypto.randomUUID()

export const loadSnippets = async (): Promise<Snippet[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as Snippet)
}

export const saveSnippet = async (input: SnippetInput): Promise<Snippet> => {
  const snippet: Snippet = {
    id: generateId(),
    title: input.title.trim(),
    language: input.language.trim().toLowerCase(),
    tags: input.tags
      .split(',')
      .map((t) => t.trim().toLowerCase())
      .filter(Boolean),
    code: input.code,
    createdAt: new Date().toISOString(),
  }
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  const newContent = existing.endsWith('\n') || existing === ''
    ? `${existing}${JSON.stringify(snippet)}\n`
    : `${existing}\n${JSON.stringify(snippet)}\n`
  await Bun.write(DATA_PATH, newContent)
  return snippet
}

export const deleteSnippet = async (id: string): Promise<boolean> => {
  const snippets = await loadSnippets()
  const filtered = snippets.filter((s) => s.id !== id)
  if (filtered.length === snippets.length) return false
  const content = filtered.map((s) => JSON.stringify(s)).join('\n') + (filtered.length ? '\n' : '')
  await Bun.write(DATA_PATH, content)
  return true
}

export const getLanguages = (snippets: Snippet[]): string[] =>
  [...new Set(snippets.map((s) => s.language))].sort()

export const getTags = (snippets: Snippet[]): string[] =>
  [...new Set(snippets.flatMap((s) => s.tags))].sort()

export const filterSnippets = (
  snippets: Snippet[],
  language: string,
  tag: string
): Snippet[] =>
  snippets.filter((s) => {
    if (language && s.language !== language) return false
    if (tag && !s.tags.includes(tag)) return false
    return true
  })

