      style: styleToStr(styles.select as unknown as Record<string, string>),
      'p-trigger': 'change:filterByTag',
    },
      h('option', { value: '' }, 'All Tags'),
      ...tags.map((tag) =>
        h('option', {
          value: tag,
          ...(tag === currentTag ? { selected: 'true' } : {}),
        }, `#${tag}`)
      ),
    ),
