export const renderEmptyState = () =>
  h('div', { style: styleToStr(styles.emptyState as unknown as Record<string, string>) },
    h('p', {}, 'No snippets yet. Add your first code snippet above!'),
  )

export const renderPage = (
  snippets: Snippet[],
  languages: string[],
  tags: string[],
  currentLang: string,
  currentTag: string,
  showForm: boolean,
) =>
  h('div', { style: styleToStr(styles.container as unknown as Record<string, string>) },
    h('div', { style: styleToStr(styles.header as unknown as Record<string, string>) },
      h('h1', { style: styleToStr(styles.title as unknown as Record<string, string>) }, 'Code Snippets'),
      h('button', {
        style: styleToStr(styles.toggleBtn as unknown as Record<string, string>),
        'p-trigger': 'click:toggleForm',
      }, showForm ? 'Cancel' : '+ New Snippet'),
    ),
    showForm ? renderSnippetForm() : h(Fragment, {}),
    renderFilterBar(languages, tags, currentLang, currentTag),
    snippets.length > 0
      ? h(Fragment, {},
          ...snippets.map(renderSnippetCard),
        )
      : renderEmptyState(),
    h('script', {}, `
      document.addEventListener('click', (e) => {
        const btn = e.target.closest('[p-trigger*="copyCode"]');
        if (!btn) return;
        const code = btn.getAttribute('data-code');
        navigator.clipboard.writeText(code).then(() => {
          const orig = btn.textContent;
          btn.textContent = 'Copied!';
          setTimeout(() => { btn.textContent = orig; }, 1500);
        });
      });
    `),
  )

import { createSSR } from 'plaited'
import { loadSnippets, saveSnippet, deleteSnippet, getLanguages, getTags, filterSnippets } from './store'
import { renderPage } from './render'
import type { SnippetInput } from './types'

const ssr = createSSR()

const buildPage = async (language = '', tag = '', showForm = false): Promise<string> => {
  const all = await loadSnippets()
  const languages = getLanguages(all)
  const tags = getTags(all)
  const filtered = filterSnippets(all, language, tag)
  const tree = renderPage(filtered, languages, tags, language, tag, showForm)
  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Code Snippets</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f8f9fa; }
    button:hover { opacity: 0.9; }
    select:focus, input:focus, textarea:focus { outline: 2px solid #6c5ce7; border-color: transparent; }
  </style>
</head>
<body>${ssr(tree)}</body>
</html>`
}

const parseFormData = async (req: Request): Promise<Record<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const result: Record<string, string> = {}
  params.forEach((value, key) => {
    result[key] = value
  })
  return result
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (req.method === 'GET' && url.pathname === '/') {
      const language = url.searchParams.get('language') ?? ''
      const tag = url.searchParams.get('tag') ?? ''
      const showForm = url.searchParams.get('form') === '1'
      const html = await buildPage(language, tag, showForm)
      return new Response(html, {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (req.method === 'POST' && url.pathname === '/snippets') {
      const data = await parseFormData(req)
      const input: SnippetInput = {
        title: data.title ?? '',
        language: data.language ?? '',
        tags: data.tags ?? '',
        code: data.code ?? '',
      }
      if (!input.title || !input.language || !input.code) {
        return new Response('Missing required fields', { status: 400 })
      }
      await saveSnippet(input)
      return Response.redirect('/', 303)
    }

    if (req.method === 'POST' && url.pathname === '/snippets/delete') {
      const data = await parseFormData(req)
      const id = data.id ?? ''
      if (id) await deleteSnippet(id)
      return Response.redirect('/', 303)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Code Snippets server running at http://localhost:${server.port}`)

import { h, Fragment } from 'plaited'
import type { Snippet } from './types'
import { styles } from './styles'

type StyleObj = Record<string, string>

const s = (obj: typeof styles[keyof typeof styles]): string =>
  Object.entries(obj)
    .map(([k, v]) => `${k.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)}:${v}`)
    .join(';')

const escapeHtml = (str: string): string =>
  str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

