    action: '/snippets',
    method: 'POST',
    style: s(styles.form),
  },
    h('div', { style: s(styles.formGroup) },
      h('label', { style: s(styles.label), for: 'snippet-title' }, 'Title'),
      h('input', {
        id: 'snippet-title',
        name: 'title',
        type: 'text',
        required: 'true',
        placeholder: 'e.g. Binary search in Python',
        style: s(styles.input),
      }),
    ),
    h('div', { style: s(styles.formGroup) },
      h('label', { style: s(styles.label), for: 'snippet-language' }, 'Language'),
      h('input', {
        id: 'snippet-language',
        name: 'language',
        type: 'text',
        required: 'true',
        placeholder: 'e.g. python, javascript, go',
        style: s(styles.input),
      }),
    ),
    h('div', { style: s(styles.formGroup) },
      h('label', { style: s(styles.label), for: 'snippet-tags' }, 'Tags (comma-separated)'),
      h('input', {
        id: 'snippet-tags',
        name: 'tags',
        type: 'text',
        placeholder: 'e.g. algorithm, search, utility',
        style: s(styles.input),
      }),
    ),
    h('div', { style: s(styles.formGroup) },
      h('label', { style: s(styles.label), for: 'snippet-code' }, 'Code'),
      h('textarea', {
