export const renderSnippetCard = (snippet: Snippet) =>
  h('div', {
    style: s(styles.snippetCard),
    'data-snippet-id': snippet.id,
  },
    h('div', { style: s(styles.snippetHeader) },
      h('h3', { style: s(styles.snippetTitle) }, snippet.title),
      h('div', { style: s(styles.actions) },
        h('span', { style: s(styles.langBadge) }, snippet.language),
        h('form', {
          action: '/snippets/delete',
          method: 'POST',
          style: 'display:inline',
        },
          h('input', { type: 'hidden', name: 'id', value: snippet.id }),
          h('button', {
            type: 'submit',
            style: s(styles.deleteBtn),
          }, 'Delete'),
        ),
      ),
    ),
    snippet.tags.length > 0
      ? h('div', { style: s(styles.tagContainer) },
          ...snippet.tags.map((tag) =>
            h('span', { style: s(styles.tag) }, `#${tag}`)
          ),
        )
      : h(Fragment, {}),
    h('div', { style: s(styles.codeWrapper) },
      h('pre', { style: s(styles.codeBlock) },
        h('code', {}, snippet.code),
      ),
      h('button', {
        type: 'button',
        style: s(styles.copyBtn),
        'data-code': escapeHtml(snippet.code),
        onclick: 'copySnippet(this)',
      }, 'Copy'),
    ),
  )

