    h('select', {
      name: 'tag',
      style: s(styles.select),
      onchange: 'this.form.submit()',
    },
      h('option', { value: '' }, 'All Tags'),
      ...tags.map((tag) =>
        h('option', {
          value: tag,
          ...(tag === currentTag ? { selected: 'selected' } : {}),
        }, `#${tag}`)
      ),
    ),
  )

export const renderEmptyState = () =>
  h('div', { style: s(styles.emptyState) },
    h('p', {}, 'No snippets yet. Add your first code snippet above!'),
  )

export const renderPage = (
  snippets: Snippet[],
  languages: string[],
  tags: string[],
  currentLang: string,
  currentTag: string,
  showForm: boolean,
) =>
  h('div', { style: s(styles.container) },
    h('div', { style: s(styles.header) },
      h('h1', { style: s(styles.title) }, 'Code Snippets'),
      h('a', {
        href: showForm ? '/' : '/?form=1',
        style: s(styles.toggleBtn) + ';text-decoration:none;display:inline-block',
      }, showForm ? 'Cancel' : '+ New Snippet'),
    ),
    showForm ? renderSnippetForm() : h(Fragment, {}),
    renderFilterBar(languages, tags, currentLang, currentTag),
    snippets.length > 0
      ? h(Fragment, {},
          ...snippets.map(renderSnippetCard),
        )
      : renderEmptyState(),
    h('script', {}, `
      const copySnippet = (btn) => {
        const code = btn.getAttribute('data-code')
          .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"');
        navigator.clipboard.writeText(code).then(() => {
          const orig = btn.textContent;
          btn.textContent = 'Copied!';
          setTimeout(() => { btn.textContent = orig; }, 1500);
        });
      };
    `),
  )
